const input = $input.first().json;
let parsed;
if (typeof input.query === 'string') {
  try { parsed = JSON.parse(input.query); } catch (e) { parsed = input; }
} else if (input.query && typeof input.query === 'object') {
  parsed = input.query;
} else {
  parsed = input;
}
// Normalize camelCase → snake_case aliases
if (!parsed.search_by) parsed.search_by = parsed.searchBy || '';
if (!parsed.search_term) parsed.search_term = parsed.searchTerm || '';
return [{ json: parsed }];

const input = $('Parse Input').first().json;
const formulas = $('Read Formulas Sheet').all();
let ingredients = [];
try { ingredients = $('Read Ingredients Sheet').all(); } catch(e) { ingredients = []; }

// Handle flexible input: {search_by, search_term} OR shorthand {function:'X'}, {phase:'X'}, {name:'X'}
let searchBy = (input.search_by || '').toLowerCase();
let term = (input.search_term || '').toLowerCase();

if (!searchBy || !term) {
  if (input.function) { searchBy = 'function'; term = String(input.function).toLowerCase(); }
  else if (input.phase) { searchBy = 'phase'; term = String(input.phase).toLowerCase(); }
  else if (input.ingredient_name || input.name) { searchBy = 'name'; term = String(input.ingredient_name || input.name).toLowerCase(); }
  else if (input.query) { searchBy = 'name'; term = String(input.query).toLowerCase(); }
  else { searchBy = searchBy || 'name'; }
}

if (!term) {
  return [{ json: { result: 'Please provide a search term. Use search_by (function/phase/name) and search_term, or provide function/phase/name directly.' } }];
}

const formulaMap = {};
for (const f of formulas) {
  formulaMap[f.json.FormulaID] = f.json.Name;
}

let matches;
if (searchBy === 'function') {
  matches = ingredients.filter(r => (r.json.Function || '').toLowerCase().includes(term));
} else if (searchBy === 'phase') {
  matches = ingredients.filter(r => (r.json.Phase || '').toLowerCase().includes(term));
} else {
  matches = ingredients.filter(r =>
    (r.json.IngredientName || '').toLowerCase().includes(term) ||
    (r.json.INCIName || '').toLowerCase().includes(term)
  );
}

if (matches.length === 0) {
  return [{ json: { result: `No ingredients found matching ${searchBy}: "${term}".` } }];
}

const lines = matches.map(r => {
  const i = r.json;
  const formulaName = formulaMap[i.FormulaID] || 'Unknown Formula';
  return `${i.IngredientName} (${i.INCIName || '-'}) - ${i.Percentage}% in "${formulaName}" | Phase: ${i.Phase} | Function: ${i.Function}`;
});

return [{ json: { result: `Found ${matches.length} match(es) for ${searchBy} "${term}":\n` + lines.join('\n') } }];
